func testAccBiglakeHiveHiveDatabase_biglakeHiveDatabaseExample(context map[string]interface{}) string {
	return acctest.Nprintf(`
terraform {
  required_providers {
    google = {
      source = "hashicorp/google-beta"
    }
  }
}

resource "google_storage_bucket" "bucket" {
  name          = "%{bucket_name}"
  location      = "us-central1"
  force_destroy = true
  uniform_bucket_level_access = true
}

resource "google_biglake_hive_catalog" "catalog" {
  name             = "tf_test_catalog%{random_suffix}"
  primary_location = "us-central1"
  location_uri     = "gs://${google_storage_bucket.bucket.name}"
}

resource "google_biglake_hive_database" "my_hive_database" {
  catalog      = google_biglake_hive_catalog.catalog.name
  name         = "tf_test_database%{random_suffix}"
  location_uri = "gs://${google_storage_bucket.bucket.name}"
  
  parameters = %{parameters}

  description = "%{description}"
}
`, context)
}

func testAccCheckBiglakeHiveHiveDatabaseDestroyProducer(t *testing.T) func(s *terraform.State) error {
	return func(s *terraform.State) error {
		for name, rs := range s.RootModule().Resources {
			if rs.Type != "google_biglake_hive_database" {
				continue
			}
			if strings.HasPrefix(name, "data.") {
				continue
			}

			config := acctest.GoogleProviderConfig(t)
			url, err := tpgresource.ReplaceVarsForTest(config, rs, transport_tpg.BaseUrl(biglakehive.Product, config)+"hive/v1beta/projects/{{project}}/catalogs/{{catalog}}/databases/{{name}}")
			if err != nil {
				return err
			}

			billingProject := ""

			if config.BillingProject != "" {
				billingProject = config.BillingProject
			}

			_, err = transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
				Config:    config,
				Method:    "GET",
				Project:   billingProject,
				RawURL:    url,
				UserAgent: config.UserAgent,
			})
			if err == nil {
				return fmt.Errorf("BiglakeHiveHiveDatabase still exists at %s", url)
			}
		}

		return nil
	}
}
